#define fp float

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    const box_str* box,
    const FOUR_VECTOR* rv,
    const fp* qv,
    FOUR_VECTOR* fv)
{
    int l = get_global_id(0);

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0f * alpha * alpha;

    long first_i = box[l].offset;
    const FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        const FOUR_VECTOR* rB = &rv[first_j];
        const fp* qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                fp r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0f * vij;

                THREE_VECTOR d;
                d.x = rA[i].x - rB[j].x;
                d.y = rA[i].y - rB[j].y;
                d.z = rA[i].z - rB[j].z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA[i].v += qB[j] * vij;
                fA[i].x += qB[j] * fxij;
                fA[i].y += qB[j] * fyij;
                fA[i].z += qB[j] * fzij;
            }
        }
    }
}
